class Solution {
    public boolean possibleBipartition(int n, int[][] dislikes) {
        int[] groups = new int[n + 1];
        Arrays.fill(groups, 0);
        for (int[] dislike : dislikes) {
            int a = dislike[0];
            int b = dislike[1];
            if (groups[a] == groups[b] || groups[a] == 0 && groups[b] == 0) {
                return false;
            }
            groups[a] = 1 - groups[b];
        }
        return true;
    }
}
```
